-- =============================================
-- Module:      order
-- File:        payment_session.sql
-- Purpose:     Lifecycle queries for the payment intent record (status transitions,
--              expiry sweeps, sibling lookups for confirm/payout flows).
-- =============================================

-- Create/Get/Delete are auto-generated by pgtempl (CreateDefaultPaymentSession / GetPaymentSession).

-- name: SetPaymentSessionData :exec
UPDATE "order"."payment_session" SET "data" = @data WHERE "id" = @id;

-- name: MarkPaymentSessionSuccess :one
UPDATE "order"."payment_session"
SET "status" = 'Success',
    "date_paid" = COALESCE(@date_paid::TIMESTAMPTZ, CURRENT_TIMESTAMP)
WHERE "id" = @id AND "status" = 'Pending'
RETURNING *;

-- name: MarkPaymentSessionFailed :one
UPDATE "order"."payment_session"
SET "status" = 'Failed'
WHERE "id" = @id AND "status" = 'Pending'
RETURNING *;

-- name: MarkPaymentSessionCancelled :one
UPDATE "order"."payment_session"
SET "status" = 'Cancelled'
WHERE "id" = @id AND "status" = 'Pending'
RETURNING *;

-- name: ListExpiredPendingSessions :many
SELECT * FROM "order"."payment_session"
WHERE "status" = 'Pending' AND "date_expired" < @cutoff::TIMESTAMPTZ
ORDER BY "date_expired"
LIMIT @limit_count::INTEGER;

-- name: GetPendingPayoutSessionForOrder :one
SELECT s.* FROM "order"."payment_session" s
WHERE s."kind" = 'seller-payout'
  AND s."status" = 'Pending'
  AND s."to_id" = (SELECT o."seller_id" FROM "order"."order" o WHERE o."id" = @order_id)
LIMIT 1;

-- name: ListCheckoutSiblingsForSession :many
-- Sibling = buyer-checkout sessions with same from_id, within ±2s of the given session.
SELECT s2.* FROM "order"."payment_session" s1
JOIN "order"."payment_session" s2 ON s2."from_id" = s1."from_id"
    AND s2."kind" = 'buyer-checkout'
    AND abs(extract(epoch from (s2."date_created" - s1."date_created"))) < 2
WHERE s1."id" = @session_id;

-- name: ListConfirmFeeSiblingsForSession :many
-- Sibling = seller-confirmation-fee sessions with same from_id, within ±2s of the given session.
SELECT s2.* FROM "order"."payment_session" s1
JOIN "order"."payment_session" s2 ON s2."from_id" = s1."from_id"
    AND s2."kind" = 'seller-confirmation-fee'
    AND abs(extract(epoch from (s2."date_created" - s1."date_created"))) < 2
WHERE s1."id" = @session_id;
